import { NextResponse } from 'next/server';
import { KalshiService } from '@/lib/services/kalshi.service';

export const dynamic = 'force-dynamic';
export const maxDuration = 60;

const KALSHI_PARLAY_PREFIXES = ['KXMVE', 'KXMULTI', 'KXCOMBO', 'KXPARLAY'];
function isParlay(ticker: string): boolean {
    return KALSHI_PARLAY_PREFIXES.some(p => ticker.startsWith(p));
}

export async function GET() {
    const kalshiService = new KalshiService();
    const pageStats: Array<{
        page: number;
        total: number;
        parlays: number;
        normal: number;
        sampleNormal: string[];
        sampleParlay: string[];
        cursor: string | null;
    }> = [];

    let cursor: string | undefined;

    for (let page = 1; page <= 15; page++) {
        const response = await kalshiService.getMarkets({
            status: 'open',
            limit: 200,
            cursor
        });

        const markets = response.markets ?? [];
        if (markets.length === 0) break;

        const parlays = markets.filter(m => isParlay(m.ticker));
        const normal = markets.filter(m => !isParlay(m.ticker));

        pageStats.push({
            page,
            total: markets.length,
            parlays: parlays.length,
            normal: normal.length,
            sampleNormal: normal.slice(0, 3).map(m => m.ticker),
            sampleParlay: parlays.slice(0, 2).map(m => m.ticker),
            cursor: response.cursor ?? null
        });

        cursor = response.cursor;
        if (!cursor) break;

        await new Promise(r => setTimeout(r, 200));
    }

    // También testear Polymarket directamente
    let polymarketStatus = '';
    try {
        const res = await fetch(
            'https://gamma-api.polymarket.com/events?active=true&closed=false&limit=5&offset=0',
            { headers: { Accept: 'application/json' } }
        );
        polymarketStatus = `HTTP ${res.status} — ${res.ok ? 'OK' : await res.text()}`;
    } catch (err) {
        polymarketStatus = `FETCH ERROR: ${err instanceof Error ? err.message : String(err)}`;
    }

    return NextResponse.json({ pageStats, polymarketStatus });
}